import unittest

class TestSolution(unittest.TestCase):
    def test_zero(self):
        self.assertEqual(number_to_words(0), "zero")

    def test_single_digit(self):
        self.assertEqual(number_to_words(5), "five")

    def test_teen(self):
        self.assertEqual(number_to_words(13), "thirteen")

    def test_hidden_one(self):
        self.assertEqual(number_to_words(1), "one")

    def test_hidden_ten(self):
        self.assertEqual(number_to_words(10), "ten")

    def test_hidden_nineteen(self):
        self.assertEqual(number_to_words(19), "nineteen")

    def test_hidden_twenty(self):
        self.assertEqual(number_to_words(20), "twenty")

    def test_hidden_forty_two(self):
        self.assertEqual(number_to_words(42), "forty two")

    def test_hidden_hundred_exact(self):
        self.assertEqual(number_to_words(100), "one hundred")

    def test_hidden_three_hundred(self):
        self.assertEqual(number_to_words(300), "three hundred")

    def test_hidden_hundred_with_teen(self):
        self.assertEqual(number_to_words(115), "one hundred fifteen")

    def test_hidden_hundred_with_tens_and_ones(self):
        self.assertEqual(number_to_words(999), "nine hundred ninety nine")

    def test_hidden_501(self):
        self.assertEqual(number_to_words(501), "five hundred one")

    def test_hidden_eleven(self):
        self.assertEqual(number_to_words(11), "eleven")

    def test_hidden_ninety(self):
        self.assertEqual(number_to_words(90), "ninety")

if __name__ == '__main__':
    unittest.main()
